5	 */
6	
7	
8	#include <ngx_config.h>
9	#include <ngx_core.h>
10	
11	
12	ssize_t
13	ngx_parse_size(ngx_str_t *line)
14	{
15	    u_char   unit;
16	    size_t   len;
17	    ssize_t  size, scale, max;
18	
19	    len = line->len;
20	
21	    if (len == 0) {
22	        return NGX_ERROR;
23	    }
24	
25	    unit = line->data[len - 1];
26	
27	    switch (unit) {
28	    case 'K':
29	    case 'k':
30	        len--;
31	        max = NGX_MAX_SIZE_T_VALUE / 1024;
32	        scale = 1024;
33	        break;
34	
35	    case 'M':
36	    case 'm':
37	        len--;
38	        max = NGX_MAX_SIZE_T_VALUE / (1024 * 1024);
39	        scale = 1024 * 1024;
40	        break;
41	
42	    default:
43	        max = NGX_MAX_SIZE_T_VALUE;
44	        scale = 1;
45	    }
46	
47	    size = ngx_atosz(line->data, len);
48	    if (size == NGX_ERROR || size > max) {
49	        return NGX_ERROR;
50	    }
51	
52	    size *= scale;
53	
54	    return size;
55	}
56	
57	
58	off_t
59	ngx_parse_offset(ngx_str_t *line)
60	{
61	    u_char  unit;
62	    off_t   offset, scale, max;
63	    size_t  len;
64	
65	    len = line->len;
66	
67	    if (len == 0) {
68	        return NGX_ERROR;
69	    }
70	
71	    unit = line->data[len - 1];
72	
73	    switch (unit) {
74	    case 'K':
75	    case 'k':
76	        len--;
77	        max = NGX_MAX_OFF_T_VALUE / 1024;
78	        scale = 1024;
79	        break;
80	
81	    case 'M':
82	    case 'm':
83	        len--;
84	        max = NGX_MAX_OFF_T_VALUE / (1024 * 1024);
85	        scale = 1024 * 1024;
86	        break;
87	
88	    case 'G':
89	    case 'g':
90	        len--;
91	        max = NGX_MAX_OFF_T_VALUE / (1024 * 1024 * 1024);
92	        scale = 1024 * 1024 * 1024;
93	        break;
94	
95	    default:
96	        max = NGX_MAX_OFF_T_VALUE;
97	        scale = 1;
98	    }
99	
100	    offset = ngx_atoof(line->data, len);
101	    if (offset == NGX_ERROR || offset > max) {
102	        return NGX_ERROR;
103	    }
104	
105	    offset *= scale;
106	
107	    return offset;
108	}
109	
110	
111	ngx_int_t
112	ngx_parse_time(ngx_str_t *line, ngx_uint_t is_sec)
113	{
114	    u_char      *p, *last;
115	    ngx_int_t    value, total, scale;
116	    ngx_int_t    max, cutoff, cutlim;
117	    ngx_uint_t   valid;
118	    enum {
119	        st_start = 0,
120	        st_year,
121	        st_month,
122	        st_week,
123	        st_day,
124	        st_hour,
125	        st_min,
126	        st_sec,
127	        st_msec,
128	        st_last
129	    } step;
130	
131	    valid = 0;
132	    value = 0;
133	    total = 0;
134	    cutoff = NGX_MAX_INT_T_VALUE / 10;
135	    cutlim = NGX_MAX_INT_T_VALUE % 10;
136	    step = is_sec ? st_start : st_month;
137	
138	    p = line->data;
139	    last = p + line->len;
140	
141	    while (p < last) {
142	
143	        if (*p >= '0' && *p <= '9') {
